passthrough_tex_frag = '\n#version 110\n\n#define saturate(x) clamp(x, 0.0, 1.0)\n\nuniform sampler2D main_texture;\n\nvarying vec2 tex_coord;\n\nvoid main() \n{\n    vec4 tex_color = texture2D(main_texture, tex_coord);\n\n    vec4 color = gl_Color * tex_color;\n\n    // do the final colouring with the fog\n    color.rgb = mix(gl_Fog.color.rgb, color.rgb, saturate((gl_Fog.end - gl_FogFragCoord) * gl_Fog.scale));\n\n    gl_FragColor = vec4(color.rgb, color.a);\n}\n'
